import React, { useState } from 'react';
import { GraduationCap, Plus, Edit, Trash2, Users, Star, DollarSign, BookOpen, TrendingUp, BarChart3, PieChart, Video, Eye, X } from 'lucide-react';

const InstructorPageNew = ({ courses, onAddCourse, onUpdateCourse, onDeleteCourse }) => {
  const [showEditModal, setShowEditModal] = useState(false);
  const [selectedCourse, setSelectedCourse] = useState(null);
  const [courseForm, setCourseForm] = useState({
    title: '',
    desc: '',
    price: ''
  });

  const editCourse = (course) => {
    setSelectedCourse(course);
    setCourseForm({
      title: course.title,
      desc: course.desc,
      price: course.price.toString()
    });
    setShowEditModal(true);
  };

  const handleEditSubmit = (e) => {
    e.preventDefault();
    if (courseForm.title && courseForm.desc && courseForm.price && selectedCourse) {
      onUpdateCourse(selectedCourse.id, {
        ...selectedCourse,
        title: courseForm.title,
        desc: courseForm.desc,
        price: parseInt(courseForm.price)
      });
      setShowEditModal(false);
      setSelectedCourse(null);
    }
  };

  return (
    <div className="min-h-screen bg-gray-100 p-8">
      <h1 className="text-3xl font-bold mb-8">Instructor Dashboard</h1>

      <div className="space-y-6">
        {courses.map(course => (
          <div key={course.id} className="bg-white p-6 rounded-lg shadow">
            <div className="flex justify-between items-center">
              <div>
                <h3 className="text-xl font-bold">{course.title}</h3>
                <p className="text-gray-600">₹{course.price}</p>
              </div>
              <button 
                onClick={() => editCourse(course)}
                className="bg-blue-500 text-white px-4 py-2 rounded hover:bg-blue-600"
              >
                Edit Course
              </button>
            </div>
          </div>
        ))}
      </div>

      {/* EDIT MODAL */}
      {showEditModal && (
        <div className="fixed inset-0 bg-black/50 flex items-center justify-center z-50">
          <div className="bg-white p-8 rounded-lg max-w-md w-full mx-4">
            <div className="flex justify-between items-center mb-6">
              <h2 className="text-2xl font-bold">Edit Course</h2>
              <button 
                onClick={() => setShowEditModal(false)}
                className="bg-red-500 text-white px-6 py-3 rounded-lg text-xl font-bold hover:bg-red-600"
              >
                CLOSE ✕
              </button>
            </div>

            <form onSubmit={handleEditSubmit} className="space-y-4">
              <input 
                type="text" 
                value={courseForm.title}
                onChange={(e) => setCourseForm({...courseForm, title: e.target.value})}
                placeholder="Course Title"
                className="w-full border p-3 rounded text-lg"
                required
              />

              <input 
                type="number" 
                value={courseForm.price}
                onChange={(e) => setCourseForm({...courseForm, price: e.target.value})}
                placeholder="Price"
                className="w-full border p-3 rounded text-lg"
                required
              />

              <textarea 
                value={courseForm.desc}
                onChange={(e) => setCourseForm({...courseForm, desc: e.target.value})}
                placeholder="Description"
                className="w-full border p-3 rounded h-24 text-lg"
                required
              />

              <div className="flex gap-4">
                <button 
                  type="submit" 
                  className="flex-1 bg-green-500 text-white py-3 rounded-lg text-xl font-bold hover:bg-green-600"
                >
                  UPDATE COURSE
                </button>
                <button 
                  type="button"
                  onClick={() => setShowEditModal(false)}
                  className="bg-gray-500 text-white px-6 py-3 rounded-lg text-xl font-bold hover:bg-gray-600"
                >
                  CANCEL
                </button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

export default InstructorPageNew;
